from collections import deque

# Stack using list
class Stack:
    def __init__(self):
        self._items = []

    def push(self, item): self._items.append(item)
    def pop(self): return self._items.pop()
    def peek(self): return self._items[-1]
    def is_empty(self): return len(self._items) == 0
    def __len__(self): return len(self._items)

# Valid parentheses — classic stack problem
def is_valid(s: str) -> bool:
    stack = []
    mapping = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()
        else:
            stack.append(char)
    return len(stack) == 0

print(is_valid("()[]{}"))  # True
print(is_valid("([)]"))    # False

# Queue using deque
class Queue:
    def __init__(self):
        self._items = deque()

    def enqueue(self, item): self._items.append(item)
    def dequeue(self): return self._items.popleft()
    def peek(self): return self._items[0]
    def is_empty(self): return len(self._items) == 0

# Monotonic stack — next greater element
def next_greater_element(nums: list) -> list:
    result = [-1] * len(nums)
    stack = []  # indices
    for i, num in enumerate(nums):
        while stack and nums[stack[-1]] < num:
            result[stack.pop()] = num
        stack.append(i)
    return result

print(next_greater_element([2, 1, 2, 4, 3]))  # [4, 2, 4, -1, -1]

# BFS with queue — level-order traversal
def bfs_level_order(root):
    if not root:
        return []
    result = []
    queue = deque([root])
    while queue:
        level = []
        for _ in range(len(queue)):
            node = queue.popleft()
            level.append(node.val)
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        result.append(level)
    return result
