from collections import deque, defaultdict
from typing import List, Set

# Graph representation — adjacency list
class Graph:
    def __init__(self):
        self.adj = defaultdict(list)

    def add_edge(self, u, v, directed=False):
        self.adj[u].append(v)
        if not directed:
            self.adj[v].append(u)

    # BFS — shortest path (unweighted)
    def bfs(self, start: int) -> List[int]:
        visited = {start}
        queue = deque([start])
        order = []
        while queue:
            node = queue.popleft()
            order.append(node)
            for neighbor in self.adj[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return order

    # DFS — recursive
    def dfs(self, start: int, visited: Set[int] = None) -> List[int]:
        if visited is None:
            visited = set()
        visited.add(start)
        order = [start]
        for neighbor in self.adj[start]:
            if neighbor not in visited:
                order.extend(self.dfs(neighbor, visited))
        return order

    # Cycle detection (directed graph)
    def has_cycle(self) -> bool:
        WHITE, GRAY, BLACK = 0, 1, 2
        color = defaultdict(int)

        def dfs(node):
            color[node] = GRAY
            for neighbor in self.adj[node]:
                if color[neighbor] == GRAY:
                    return True  # back edge = cycle
                if color[neighbor] == WHITE and dfs(neighbor):
                    return True
            color[node] = BLACK
            return False

        return any(dfs(node) for node in self.adj if color[node] == WHITE)

    # Topological sort (DAG)
    def topo_sort(self) -> List[int]:
        visited = set()
        order = []

        def dfs(node):
            visited.add(node)
            for neighbor in self.adj[node]:
                if neighbor not in visited:
                    dfs(neighbor)
            order.append(node)  # post-order

        for node in self.adj:
            if node not in visited:
                dfs(node)
        return order[::-1]

# Number of islands (grid BFS)
def num_islands(grid: List[List[str]]) -> int:
    if not grid:
        return 0
    count = 0
    rows, cols = len(grid), len(grid[0])

    def bfs(r, c):
        queue = deque([(r, c)])
        grid[r][c] = '0'  # mark visited
        while queue:
            for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == '1':
                    grid[nr][nc] = '0'
                    queue.append((nr, nc))

    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == '1':
                bfs(r, c)
                count += 1
    return count
